/// {@category Misc}
library;

// Dart imports:
import 'dart:async';

// Flutter imports:
import 'package:flutter/widgets.dart';

// Package imports:
import 'package:freezed_annotation/freezed_annotation.dart';

part 'navigation_streamer.freezed.dart';

enum NavigationType {
  didPush,
  didPop,
  didRemove,
  didReplace,
}

@freezed
abstract class NavigationEvent with _$NavigationEvent {
  factory NavigationEvent({
    required NavigationType type,
    required Route? primaryRoute,
    required Route? secondaryRoute,
  }) = _NavigationEvent;
}

class NavigationStreamer extends NavigatorObserver {
  final _controller = StreamController<NavigationEvent>.broadcast();

  Stream<NavigationEvent> get stream => _controller.stream;

  @override
  void didPush(Route route, Route? previousRoute) {
    _controller.add(NavigationEvent(
      type: NavigationType.didPush,
      primaryRoute: route,
      secondaryRoute: previousRoute,
    ));
  }

  @override
  void didPop(Route route, Route? previousRoute) {
    _controller.add(NavigationEvent(
      type: NavigationType.didPop,
      primaryRoute: route,
      secondaryRoute: previousRoute,
    ));
  }

  @override
  void didRemove(Route route, Route? previousRoute) {
    _controller.add(NavigationEvent(
      type: NavigationType.didRemove,
      primaryRoute: route,
      secondaryRoute: previousRoute,
    ));
  }

  @override
  void didReplace({Route? newRoute, Route? oldRoute}) {
    _controller.add(NavigationEvent(
      type: NavigationType.didReplace,
      primaryRoute: newRoute,
      secondaryRoute: oldRoute,
    ));
  }
}

