/// {@category Containers}
library;

// Flutter imports:
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/notification_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_domain.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_level.dart';
import 'package:baseball_detector_flutter/data/models/user_info.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/utils/build_context_ext.dart';
import 'package:baseball_detector_flutter/views/hooks/use_single_team_check.dart';
import 'package:baseball_detector_flutter/views/pages/home/hooks/use_upload_queue_event.dart';
import 'package:baseball_detector_flutter/views/routers/home_router.dart';
import 'package:baseball_detector_flutter/views/routers/navigation_logger.dart';

class HomePage extends HookConsumerWidget {
  const HomePage({super.key});

  static const bodyPadding = EdgeInsets.symmetric(horizontal: 16);

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final isSingleTeam = useSingleTeamCheck();
    final currentIndex = useValueNotifier<int>(0);
    final currentPath = useValueNotifier<String?>(null);

    final tabs = _getAvailableTabs(context, ref, isSingleTeam);
    final tabIndices = Map.fromEntries(
        tabs.asMap().entries.map((e) => MapEntry(e.value.tab, e.key)));

    // RecordingPage では独自に UploadEvent を処理する
    useUploadQueueEvent();

    final navigator = Navigator(
      key: homeRouterKey,
      onGenerateRoute: (settings) {
        switch (settings.name) {
          case HomeRouter.sessionsPage:
          case HomeRouter.playersPage:
          case HomeRouter.singleTeamPlayerPage:
          case HomeRouter.adminPage:
          case HomeRouter.settingsPage:
            final page = HomeRouter.getPage(context, settings);
            return PageRouteBuilder(
              settings: settings,
              pageBuilder: (_, __, ___) => page,
            );
          default:
            final page = HomeRouter.getPage(context, settings);
            return MaterialPageRoute(settings: settings, builder: (_) => page);
        }
      },
      observers: [
        _NavigatorObserver(pathChanged: (path) {
          currentPath.value = path;
          if (path != null) {
            final newIndex = tabIndices[HomeRouter.getTab(path)] ?? 0;
            // Ensure the new index is within valid range
            currentIndex.value =
                newIndex < tabs.length ? newIndex : tabs.length - 1;
          }
        }),
        NavigationLogger(name: 'HomeRouter'),
        homeRouterObserver,
        homeRouterStreamer,
      ],
    );

    return PopScope(
      canPop: false,
      onPopInvokedWithResult: (didPop, result) async {
        _onBackButtonPressed();
      },
      child: Scaffold(
        body: context.isPortrait
            ? navigator
            : Row(
                children: [
                  _buildSideNavigationBar(
                      tabs, currentIndex, currentPath, tabIndices),
                  Expanded(child: navigator),
                ],
              ),
        bottomNavigationBar: context.isPortrait
            ? _buildBottomNavigationBar(
                tabs, currentIndex, currentPath, tabIndices)
            : null,
      ),
    );
  }

  List<_TabItem> _getAvailableTabs(
      BuildContext context, WidgetRef ref, bool isSingleTeam) {
    final teamId = ref.watch(profileStorageProvider).getTeamId();
    final accessibleContents =
        ref.watch(userAccessibleContentsControllerProvider);

    final tabs = <_TabItem>[];

    tabs.add(_TabItem(
      tab: HomeTabs.sessions,
      icon: Icon(Icons.list_outlined),
      label: context.l10n.home_page__sessions,
      path: HomeRouter.sessionsPage,
    ));

    if (isSingleTeam) {
      tabs.add(
        _TabItem(
          tab: HomeTabs.players,
          icon: Icon(Icons.person_outline),
          label: context.l10n.home_page__player,
          path: HomeRouter.singleTeamPlayerPage,
        ),
      );
    } else {
      tabs.add(
        _TabItem(
          tab: HomeTabs.players,
          icon: Icon(Icons.group_outlined),
          label: context.l10n.home_page__players,
          path: HomeRouter.playersPage,
        ),
      );
    }

    if (accessibleContents != null && teamId != null) {
      if (accessibleContents.hasPrivilegesFor(
          teamId, RoleDomain.management, RoleLevel.read, true)) {
        tabs.add(_TabItem(
          tab: HomeTabs.admin,
          icon: Icon(Icons.manage_accounts_outlined),
          label: context.l10n.home_page__admin,
          path: HomeRouter.adminPage,
        ));
      }
    }

    // 未読通知の有無をチェック
    final hasUnread = ref.watch(showNotiBadgeProvider);

    tabs.add(_TabItem(
      tab: HomeTabs.settings,
      icon: hasUnread.value == true
          ? Stack(
              alignment: Alignment.topRight,
              children: [
                Container(
                  width: 8,
                  height: 8,
                  decoration: const BoxDecoration(
                    color: Colors.red,
                    shape: BoxShape.circle,
                  ),
                ),
                Icon(Icons.settings_outlined),
              ],
            )
          : Icon(Icons.settings_outlined),
      label: context.l10n.home_page__settings,
      path: HomeRouter.settingsPage,
    ));

    return tabs;
  }

  Widget _buildBottomNavigationBar(
    List<_TabItem> tabs,
    ValueNotifier<int> currentIndex,
    ValueNotifier<String?> currentPath,
    Map<HomeTabs, int> tabIndices,
  ) {
    final items = tabs.map<BottomNavigationBarItem>((tab) {
      return BottomNavigationBarItem(
        icon: tab.icon,
        label: tab.label,
      );
    }).toList();

    return Consumer(
      builder: (context, ref, child) {
        // Watch UserAccessibleContentsController to handle state changes during team switching
        ref.watch(userAccessibleContentsControllerProvider);

        // Restore currentIndex based on current path when tabs change
        WidgetsBinding.instance.addPostFrameCallback((_) {
          if (currentPath.value != null) {
            final currentTab = HomeRouter.getTab(currentPath.value!);
            final newIndex = tabIndices[currentTab] ?? 0;
            final validIndex =
                newIndex < tabs.length ? newIndex : tabs.length - 1;
            if (currentIndex.value != validIndex) {
              currentIndex.value = validIndex;
            }
          }
        });

        return ListenableBuilder(
          listenable: currentIndex,
          builder: (context, _) {
            // Ensure currentIndex is within valid range
            final safeCurrentIndex = currentIndex.value >= tabs.length
                ? tabs.length - 1
                : currentIndex.value;

            // Update currentIndex if it was out of range
            if (safeCurrentIndex != currentIndex.value) {
              WidgetsBinding.instance.addPostFrameCallback((_) {
                currentIndex.value = safeCurrentIndex;
              });
            }

            return BottomNavigationBar(
              type: BottomNavigationBarType.fixed,
              items: items,
              onTap: (int index) {
                final path = tabs[index].path;
                if (path != currentPath.value &&
                    homeRouterKey.currentState != null) {
                  // Clear the back stack and push the new path
                  homeRouterKey.currentState!
                    ..popUntil((route) => route.isFirst)
                    ..pushNamed(path);
                }
              },
              currentIndex: safeCurrentIndex,
            );
          },
        );
      },
    );
  }

  Widget _buildSideNavigationBar(
    List<_TabItem> tabs,
    ValueNotifier<int> currentIndex,
    ValueNotifier<String?> currentPath,
    Map<HomeTabs, int> tabIndices,
  ) {
    final destinations = tabs.map<NavigationRailDestination>((tab) {
      return NavigationRailDestination(
        icon: tab.icon,
        label: Text(tab.label),
      );
    }).toList();

    return Consumer(
      builder: (context, ref, child) {
        // Watch UserAccessibleContentsController to handle state changes during team switching
        ref.watch(userAccessibleContentsControllerProvider);

        // Restore currentIndex based on current path when tabs change
        WidgetsBinding.instance.addPostFrameCallback((_) {
          if (currentPath.value != null) {
            final currentTab = HomeRouter.getTab(currentPath.value!);
            final newIndex = tabIndices[currentTab] ?? 0;
            final validIndex =
                newIndex < tabs.length ? newIndex : tabs.length - 1;
            if (currentIndex.value != validIndex) {
              currentIndex.value = validIndex;
            }
          }
        });

        return ValueListenableBuilder<int>(
          valueListenable: currentIndex,
          builder: (context, currentIndexValue, _) {
            // Ensure currentIndex is within valid range
            final safeCurrentIndex = currentIndexValue >= tabs.length
                ? tabs.length - 1
                : currentIndexValue;

            // Update currentIndex if it was out of range
            if (safeCurrentIndex != currentIndexValue) {
              WidgetsBinding.instance.addPostFrameCallback((_) {
                currentIndex.value = safeCurrentIndex;
              });
            }

            return NavigationRail(
              selectedIndex: safeCurrentIndex,
              onDestinationSelected: (int index) {
                final path = tabs[index].path;
                if (path != currentPath.value &&
                    homeRouterKey.currentState != null) {
                  // Clear the back stack
                  homeRouterKey.currentState!
                    ..popUntil((route) => route.isFirst)
                    ..pushNamed(path);
                }
              },
              labelType: NavigationRailLabelType.all,
              destinations: destinations,
            );
          },
        );
      },
    );
  }

  void _onBackButtonPressed() {
    if (homeRouterKey.currentState?.canPop() == true) {
      homeRouterKey.currentState!.pop();
      return;
    }
    SystemNavigator.pop();
  }
}

class _TabItem {
  final HomeTabs tab;
  final Widget icon;
  final String label;
  final String path;

  _TabItem({
    required this.tab,
    required this.icon,
    required this.label,
    required this.path,
  });
}

class _NavigatorObserver extends NavigatorObserver {
  _NavigatorObserver({required this.pathChanged});

  final ValueChanged<String?> pathChanged;

  void _onRouteChange(Route? route) {
    pathChanged(route?.settings.name);
  }

  @override
  void didPush(Route route, Route? previousRoute) => _onRouteChange(route);

  @override
  void didPop(Route route, Route? previousRoute) =>
      _onRouteChange(previousRoute);

  @override
  void didRemove(Route route, Route? previousRoute) =>
      _onRouteChange(previousRoute);

  @override
  void didReplace({Route? newRoute, Route? oldRoute}) =>
      _onRouteChange(newRoute);
}

