   106→
   107→      case AuthHubEventType.sessionExpired:
   108→        CloudWatch.instance.userId = null;
   109→        _logger.w('received session expired event');
   110→
   111→      case AuthHubEventType.userDeleted:
   112→        CloudWatch.instance.userId = null;
   113→        _logger.i('received user deleted event');
   114→    }
   115→  });
