   117→  // Flutterの標準ライセンスに追加
   118→  CustomLicensePage.addSILLicense();
   119→
   120→  // それぞれの処理が独立しているので並行に実行
   121→  await Future.wait([
   122→    _recordSignedIn(),
   123→    LocalVideoStorage.loadSingleton(),
   124→    BackgroundHttpClient.initialize(),
