   207→
   208→    return GestureDetector(
   209→      behavior: HitTestBehavior.opaque,
   210→      onTap: () => WidgetsBinding.instance.focusManager.primaryFocus?.unfocus(),
   211→      child: MaterialApp(
   212→        title: 'Baseball Detector',
   213→        localizationsDelegates: L10n.localizationsDelegates,
   214→        supportedLocales: L10n.supportedLocales,
   215→        theme: isDarkMode ? AppTheme.dark.data : AppTheme.light.data,
   216→        home: const SplashPage(),
   217→        debugShowCheckedModeBanner: false,
   218→        locale: localeLanguage,
   219→        // initialRoute: AppRouter.splashPage, // Do not use initialRoute. See https://qiita.com/youmeee/items/c71e4d906ef93f3b228b
   220→        onGenerateRoute: AppRouter.generateRoute,
   221→        navigatorObservers: [
   222→          NavigationLogger(
   223→            name: 'AppRouter',
   224→            ignoreRouteNames: AppRouter.ignoreRoutesForLogging,
   225→          ),
   226→          appRouterObserver,
   227→          appRouterStreamer,
   228→        ],
   229→        navigatorKey: appRouterKey,
   230→      ),
   231→    );
   232→  }
   233→
   234→  @override
   235→  void onInMaintenance() {
   236→    _isOnMaintenancePage = true;
   237→
   238→    // navigate to maintenance page
   239→    appRouterKey.currentState!.pushNamedAndRemoveUntil(
   240→      AppRouter.maintenancePage,
   241→      (_) => false,
   242→    );
   243→  }
   244→
   245→  @override
   246→  void onMaintenanceEnded() {
   247→    _isOnMaintenancePage = false;
   248→
   249→    // reset internal state so that the update message appears again
   250→    VersionController.reset();
   251→
   252→    // navigate to splash page
   253→    appRouterKey.currentState!.pushNamedAndRemoveUntil(
   254→      AppRouter.splashPage,
   255→      (_) => false,
   256→    );
   257→  }
   258→
   259→  @override
   260→  void onNewVersionAvailable() {
   261→    // No update notifications during maintenance
   262→    // (maintenance notifications take precedence)
   263→    if (_isOnMaintenancePage) {
   264→      return;
   265→    }
   266→
   267→    final updateInfo = ref.read(versionControllerProvider).value!.right;
   268→
   269→    showDialog(
   270→      // NOTE: Use the appRouterKey context here, otherwise the dialog transition will not work.
   271→      context: appRouterKey.currentState!.context,
   272→      barrierDismissible: true,
   273→      routeSettings: const RouteSettings(name: AppRouter.updateAvailableDialog),
   274→      builder: (context) {
   275→        return UpdateAvailableDialog(
   276→          updateInfo: updateInfo,
   277→        );
   278→      },
   279→    );
   280→  }
   281→
   282→  @override
   283→  void onNewVersionRequired() {
   284→    // No update notifications during maintenance
   285→    // (maintenance notifications take precedence)
   286→    if (_isOnMaintenancePage) {
   287→      return;
   288→    }
   289→
   290→    // navigate to force update page
   291→    appRouterKey.currentState!.pushNamedAndRemoveUntil(
   292→      AppRouter.updateRequiredPage,
   293→      (_) => false,
   294→    );
   295→  }
   296→
   297→  @override
   298→  void onNewVersionRequirementWithdrawn() {
   299→    // No update notifications during maintenance
   300→    // (maintenance notifications take precedence)
   301→    if (_isOnMaintenancePage) {
   302→      return;
   303→    }
   304→
   305→    // navigate to splash page
   306→    appRouterKey.currentState!.pushNamedAndRemoveUntil(
   307→      AppRouter.splashPage,
   308→      (_) => false,
   309→    );
   310→  }
   311→
   312→  @override
   313→  void didChangeAppLifecycleState(AppLifecycleState state) {
   314→    _logger.i('AppLifecycleState changed: ${state.name}');
   315→
   316→    if (state == AppLifecycleState.paused) {
   317→      _onPaused();
   318→    } else if (state == AppLifecycleState.resumed) {
   319→      _onResumed();
   320→    }
   321→  }
   322→
   323→  void _onPaused() {
   324→    ref.read(maintenanceControllerProvider.notifier).stopObserving();
   325→    ref.read(versionControllerProvider.notifier).stopObserving();
   326→    _pausedSince = DateTime.now().toUtc();
   327→  }
   328→
   329→  void _onResumed() {
   330→    ref.read(maintenanceControllerProvider.notifier).startObserving(true);
   331→    ref.refresh(versionControllerProvider.notifier).startObserving(false);
   332→
   333→    if (_pausedSince == null) return;
   334→
   335→    if (DateTime.now().isAfter(_pausedSince!.add(_invalidateAfter))) {
   336→      _logger.i('invalidating providers');
   337→
   338→      ref.invalidate(sessionListControllerProvider);
   339→      ref.invalidate(resourceDataListControllerProvider);
   340→      ref.invalidate(resourceDataDetailControllerProvider);
   341→      ref.invalidate(userInfoControllerProvider);
   342→      ref.invalidate(memberListControllerProvider);
   343→      ref.invalidate(playerListControllerProvider);
   344→      ref.invalidate(teamListControllerProvider);
   345→
   346→      // Refresh user's accessible contents when app resumes after long pause
   347→      ref.read(userAccessibleContentsControllerProvider.notifier).refresh();
   348→    }
   349→
   350→    _pausedSince = null;
   351→  }
   352→}
