// Project imports:
import 'package:baseball_detector_flutter/controllers/app_version_controller.dart';
import 'package:baseball_detector_flutter/controllers/locale_controller.dart';
import 'package:baseball_detector_flutter/controllers/maintenance_controller.dart';
import 'package:baseball_detector_flutter/controllers/member_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/player_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/resource_data_detail_controller.dart';
import 'package:baseball_detector_flutter/controllers/resource_data_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/session_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/subscription_controller.dart';
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_info_controller.dart';
import 'package:baseball_detector_flutter/controllers/version_controller.dart';
import 'package:baseball_detector_flutter/data/clients/background_http_client.dart';
import 'package:baseball_detector_flutter/data/models/local_video.dart';
import 'package:baseball_detector_flutter/l10n/l10n.dart';
import 'package:baseball_detector_flutter/logging.dart';
import 'package:baseball_detector_flutter/modules/amplify/amplify.dart';
import 'package:baseball_detector_flutter/providers/custom_provider_observer.dart';
import 'package:baseball_detector_flutter/providers/dark_mode_provider.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/utils/screen_orientation.dart';
import 'package:baseball_detector_flutter/views/components/update_available_dialog.dart';
import 'package:baseball_detector_flutter/views/pages/home/settings/custom_license/custom_license_page.dart';
import 'package:baseball_detector_flutter/views/pages/splash/splash_page.dart';
import 'package:baseball_detector_flutter/views/routers/app_router.dart';
import 'package:baseball_detector_flutter/views/routers/navigation_logger.dart';
import 'package:baseball_detector_flutter/views/themes/app_theme.dart';
import 'package:baseball_detector_flutter/views/themes/system_ui_overlay.dart';

final _logger = FimberLog('Main');

/// Initializes services and controllers before the start of the application
Future<ProviderContainer> _createProviderContainer() async {
  final container = ProviderContainer(
    overrides: [
      // A trick to make `sharedPreferencesProvider` just a `Provider`.
      // See: https://zenn.dev/riscait/books/flutter-riverpod-practical-introduction-archive/viewer/v0-shared-preferences (in Japanese)
      sharedPreferencesProvider.overrideWithValue(
        await SharedPreferences.getInstance(),
      ),
    ],
    observers: [
      CustomProviderObservers(),
    ],
  );

  // NOTE: required when [AuthClient.restoreSession] is called in [LoginStateController]
  // and the app starts with [LoginPage].
  // container.read(authClientProvider);

  return container;
}

/// Entrypoint
void main() async {
  WidgetsFlutterBinding.ensureInitialized();

  // StoreKit 2 の初期化
  InAppPurchaseStoreKitPlatform.registerPlatform();

  final container = await _createProviderContainer();

  // Logger and Amplify
  final terminalId = await _getOrGenerateTerminalId(container);
  await initLogging(terminalId);
  _logger.i('initialized');

  Amplify.Hub.listen(HubChannel.Auth, (data) async {
    switch (data.type) {
      case AuthHubEventType.signedIn:
        await _recordSignedIn();

      case AuthHubEventType.signedOut:
        CloudWatch.instance.userId = null;
        _logger.i('received signed out event');

      case AuthHubEventType.sessionExpired:
        CloudWatch.instance.userId = null;
        _logger.w('received session expired event');

      case AuthHubEventType.userDeleted:
        CloudWatch.instance.userId = null;
        _logger.i('received user deleted event');
    }
  });

  // Flutterの標準ライセンスに追加
  CustomLicensePage.addSILLicense();

  // それぞれの処理が独立しているので並行に実行
  await Future.wait([
    _recordSignedIn(),
    LocalVideoStorage.loadSingleton(),
    BackgroundHttpClient.initialize(),
    container.read(appVersionControllerProvider.notifier).update(),
  ]);

  container.read(subscriptionControllerProvider);

  runApp(
    UncontrolledProviderScope(
      container: container,
      child: const App(),
    ),
  );
}

/// Gets the device ID. If it has not been generated yet, it will generate one
/// and return it.
Future<String> _getOrGenerateTerminalId(ProviderContainer container) async {
  // NOTE: place this function here since we want to use Ref from external files
  // and do not want to expose ProviderContainer outside of this file

  final profileStorage = container.read(profileStorageProvider);

  // NOTE: Lowercasing and validation to prevent parameter manipulation
  var terminalId = profileStorage.getTerminalId()?.toLowerCase();
  if (terminalId == null || !Uuid.isValidUUID(fromString: terminalId)) {
    terminalId = const Uuid().v4().toString();
    await profileStorage.setTerminalId(terminalId);
  }

  return terminalId;
}

Future<void> _recordSignedIn() async {
  try {
    final userId = await AuthUtils.instance.getUserId();
    CloudWatch.instance.userId = userId;
    _logger.i('received signed in event: $userId');
  } on SignedOutException {
    _logger.i('not signed in');
    CloudWatch.instance.userId = null;
  } catch (e) {
    _logger.e('failed to get session information', ex: e);
    CloudWatch.instance.userId = null;
  }
}

/// The root widget of this app.
class App extends ConsumerStatefulWidget {
  const App({super.key});

  @override
  ConsumerState<ConsumerStatefulWidget> createState() => _AppState();
}

class _AppState extends ConsumerState<App>
    with WidgetsBindingObserver
    implements MaintenanceControllerHandlers, VersionControllerHandlers {
  static const _invalidateAfter = Duration(days: 1);
  DateTime? _pausedSince;
  bool _isOnMaintenancePage = false;

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addObserver(this);
    MaintenanceController.registerHandlers(this);
    VersionController.registerHandlers(this);
  }

  @override
  void dispose() {
    WidgetsBinding.instance.removeObserver(this);
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final isDarkMode = ref.watch(darkModeProvider);
    final localeLanguage = ref.watch(localeControllerProvider);

    ScreenOrientation.setDefault();
    SystemUiOverlayColorScheme.instance.apply(isDarkMode);
    SystemChrome.setEnabledSystemUIMode(SystemUiMode.edgeToEdge);

    return GestureDetector(
      behavior: HitTestBehavior.opaque,
      onTap: () => WidgetsBinding.instance.focusManager.primaryFocus?.unfocus(),
      child: MaterialApp(
        title: 'Baseball Detector',
        localizationsDelegates: L10n.localizationsDelegates,
        supportedLocales: L10n.supportedLocales,
        theme: isDarkMode ? AppTheme.dark.data : AppTheme.light.data,
        home: const SplashPage(),
        debugShowCheckedModeBanner: false,
        locale: localeLanguage,
        // initialRoute: AppRouter.splashPage, // Do not use initialRoute. See https://qiita.com/youmeee/items/c71e4d906ef93f3b228b
        onGenerateRoute: AppRouter.generateRoute,
        navigatorObservers: [
          NavigationLogger(
            name: 'AppRouter',
            ignoreRouteNames: AppRouter.ignoreRoutesForLogging,
          ),
          appRouterObserver,
          appRouterStreamer,
        ],
        navigatorKey: appRouterKey,
      ),
    );
  }

  @override
  void onInMaintenance() {
    _isOnMaintenancePage = true;

    // navigate to maintenance page
    appRouterKey.currentState!.pushNamedAndRemoveUntil(
      AppRouter.maintenancePage,
      (_) => false,
    );
  }

  @override
  void onMaintenanceEnded() {
    _isOnMaintenancePage = false;

    // reset internal state so that the update message appears again
    VersionController.reset();

    // navigate to splash page
    appRouterKey.currentState!.pushNamedAndRemoveUntil(
      AppRouter.splashPage,
      (_) => false,
    );
  }

  @override
  void onNewVersionAvailable() {
    // No update notifications during maintenance
    // (maintenance notifications take precedence)
    if (_isOnMaintenancePage) {
      return;
    }

    final updateInfo = ref.read(versionControllerProvider).value!.right;

    showDialog(
      // NOTE: Use the appRouterKey context here, otherwise the dialog transition will not work.
      context: appRouterKey.currentState!.context,
      barrierDismissible: true,
      routeSettings: const RouteSettings(name: AppRouter.updateAvailableDialog),
      builder: (context) {
        return UpdateAvailableDialog(
          updateInfo: updateInfo,
        );
      },
    );
  }

  @override
  void onNewVersionRequired() {
    // No update notifications during maintenance
    // (maintenance notifications take precedence)
    if (_isOnMaintenancePage) {
      return;
    }

    // navigate to force update page
    appRouterKey.currentState!.pushNamedAndRemoveUntil(
      AppRouter.updateRequiredPage,
      (_) => false,
    );
  }

  @override
  void onNewVersionRequirementWithdrawn() {
    // No update notifications during maintenance
    // (maintenance notifications take precedence)
    if (_isOnMaintenancePage) {
      return;
    }

    // navigate to splash page
    appRouterKey.currentState!.pushNamedAndRemoveUntil(
      AppRouter.splashPage,
      (_) => false,
    );
  }

  @override
  void didChangeAppLifecycleState(AppLifecycleState state) {
    _logger.i('AppLifecycleState changed: ${state.name}');

    if (state == AppLifecycleState.paused) {
      _onPaused();
    } else if (state == AppLifecycleState.resumed) {
      _onResumed();
    }
  }

  void _onPaused() {
    ref.read(maintenanceControllerProvider.notifier).stopObserving();
    ref.read(versionControllerProvider.notifier).stopObserving();
    _pausedSince = DateTime.now().toUtc();
  }

  void _onResumed() {
    ref.read(maintenanceControllerProvider.notifier).startObserving(true);
    ref.refresh(versionControllerProvider.notifier).startObserving(false);

    if (_pausedSince == null) return;

    if (DateTime.now().isAfter(_pausedSince!.add(_invalidateAfter))) {
      _logger.i('invalidating providers');

      ref.invalidate(sessionListControllerProvider);
      ref.invalidate(resourceDataListControllerProvider);
      ref.invalidate(resourceDataDetailControllerProvider);
      ref.invalidate(userInfoControllerProvider);
      ref.invalidate(memberListControllerProvider);
      ref.invalidate(playerListControllerProvider);
      ref.invalidate(teamListControllerProvider);

      // Refresh user's accessible contents when app resumes after long pause
      ref.read(userAccessibleContentsControllerProvider.notifier).refresh();
    }

    _pausedSince = null;
  }
}

