     7→import 'package:flutter/material.dart';
     8→
     9→// Package imports:
    10→import 'package:flutter_hooks/flutter_hooks.dart';
    11→
    12→// Project imports:
    13→import 'package:baseball_detector_flutter/views/routers/app_router.dart';
    14→import 'package:baseball_detector_flutter/views/routers/navigation_state_extension.dart';
    15→import 'package:baseball_detector_flutter/views/themes/color_manager.dart';
    16→
    17→/// A custom loading indicator widget.
    18→class CustomLoadingIndicator extends StatelessWidget {
    19→  final double? progress;
    20→
    21→  const CustomLoadingIndicator({super.key, this.progress});
    22→
    23→  @override
    24→  Widget build(BuildContext context) {
    25→    final loadingIndicator = SizedBox(
    26→      width: 32,
    27→      height: 32,
    28→      child: TweenAnimationBuilder(
    29→        tween: Tween(begin: 0.0, end: progress ?? 0.0),
    30→        duration: const Duration(milliseconds: 250),
    31→        curve: Curves.easeOut,
    32→        builder: (context, value, _) => RepaintBoundary(
    33→          // RepaintBoundaryを追加してアニメーションを最適化
    34→          child: CircularProgressIndicator(
    35→            color: ColorManager.blueCrayola,
    36→            strokeWidth: 2.5,
    37→            value: progress != null && progress != 0 ? value : null,
    38→          ),
    39→        ),
    40→      ),
    41→    );
    42→
    43→    // Apply clamping to filter invalid values
    44→    // It may take a negative value when an error occurs or the function is
    45→    // canceled. This is for convenience, although filtering should be done on
    46→    // the caller side.
    47→    final text =
    48→        progress != null ? '${(progress! * 100).toInt().clamp(0, 100)}%' : null;
    49→    final textIsNotEmpty = text?.isNotEmpty ?? false;
    50→    return Center(
    51→      child: Container(
    52→        width: 100,
    53→        height: 100,
    54→        padding: const EdgeInsets.all(10),
    55→        decoration: BoxDecoration(
    56→          borderRadius: const BorderRadius.all(Radius.circular(10)),
    57→          color: ColorManager.blueCrayola.withValues(alpha: 0.5),
    58→        ),
    59→        child: Column(
    60→          mainAxisAlignment: MainAxisAlignment.center,
    61→          children: [
    62→            loadingIndicator,
    63→            Visibility(
    64→              visible: textIsNotEmpty,
    65→              child: Padding(
    66→                padding: const EdgeInsets.only(top: 8),
    67→                child: Text(
    68→                  text ?? '',
    69→                  overflow: TextOverflow.ellipsis,
