### リダイレクトロジック

```dart
String? _globalRedirect(BuildContext context, GoRouterState state) {
  final ref = ProviderScope.containerOf(context);

  // システムチェック（優先度高）
  if (Constants.isDeprecated && state.matchedLocation != '/force-migration') {
    return '/force-migration';
  }

  final maintenance = ref.read(maintenanceControllerProvider);
  if (maintenance.value?.isInMaintenance == true &&
      state.matchedLocation != '/maintenance') {
    return '/maintenance';
  }

  final version = ref.read(versionControllerProvider);
  if (version.value?.isRight == true &&
      version.value!.right.isUpdateRequired &&
      state.matchedLocation != '/update-required') {
    return '/update-required';
  }

  // 認証チェック（優先度低）
  final isPublicRoute = [
    '/splash',
    '/force-migration',
    '/maintenance',
    '/update-required',
    '/onboarding',
    '/login',
    '/signup',
  ].any((route) => state.matchedLocation.startsWith(route));

  if (!isPublicRoute) {
    final authClient = ref.read(authClientProvider);
    final isLoggedIn = authClient.isLoggedIn; // 同期版を用意する必要がある

    if (!isLoggedIn) {
      return '/login';
    }
  }

  return null;
}

String? _adminRedirect(BuildContext context, GoRouterState state) {
  final ref = ProviderScope.containerOf(context);
  final accessibleContents = ref.read(userAccessibleContentsControllerProvider);
  final teamId = ref.read(profileStorageProvider).getTeamId();

  if (accessibleContents == null || teamId == null) {
    return '/home/sessions';
  }

  if (!accessibleContents.hasPrivilegesFor(
      teamId, RoleDomain.management, RoleLevel.read, true)) {
    return '/home/sessions';
  }

  return null;
}
```

