```dart
class LoadingDialogManager {
  final GoRouter _router;
  VoidCallback? _listener;

  LoadingDialogManager(this._router);

  Future<bool> popLoadingDialogWhenRouteChanges({
    required BuildContext context,
    required Route dialog,
  }) async {
    final completer = Completer<bool>();

    _listener = () {
      if (!completer.isCompleted) {
        final result = _tryToPopLoadingDialog(context: context, dialog: dialog);
        if (result != null) {
          completer.complete(result);
          _router.routerDelegate.removeListener(_listener!);
        }
      }
    };

    _router.routerDelegate.addListener(_listener!);

    return completer.future;
  }

  bool? _tryToPopLoadingDialog({
    required BuildContext context,
    required Route dialog,
  }) {
    if (dialog.isCurrent) {
      Navigator.of(context, rootNavigator: true).pop();
      return true;
    }
    if (!dialog.isActive) {
      return false;
    }
    return null;
  }
}
```

