      final result = _globalRedirect(context, state);

      // Verify
      expect(result, '/force-migration');
    });

    test('メンテナンス中は /maintenance にリダイレクト', () {
      // ...
    });

    test('未ログイン時は /login にリダイレクト', () {
      // ...
    });
