## 新しいルーティング構造

### ルート定義

```dart
final goRouter = GoRouter(
  initialLocation: '/splash',
  navigatorKey: _rootNavigatorKey,
  observers: [
    NavigationLogger(name: 'GoRouter'),
  ],
  redirect: _globalRedirect,
  routes: [
    // システムページ（認証不要）
    GoRoute(
      path: '/splash',
      builder: (context, state) => const SplashPage(),
    ),
    GoRoute(
      path: '/force-migration',
      builder: (context, state) => const ForceMigrationPage(),
    ),
    GoRoute(
      path: '/maintenance',
      builder: (context, state) => const MaintenancePage(),
    ),
    GoRoute(
      path: '/update-required',
      builder: (context, state) => const UpdateRequiredPage(),
    ),

    // 認証フロー
    GoRoute(
      path: '/onboarding',
      builder: (context, state) => const OnboardingPage(),
    ),
    GoRoute(
      path: '/login',
      builder: (context, state) => const LoginPage(),
      routes: [
        GoRoute(
          path: 'forgot-password',
          builder: (context, state) => const ForgotPasswordPage(),
        ),
      ],
    ),
    GoRoute(
      path: '/signup',
      builder: (context, state) => const SignUpPage(),
      routes: [
        GoRoute(
          path: 'confirm-code',
          builder: (context, state) => const ConfirmCodePage(),
        ),
      ],
    ),

    // メインアプリ（認証必要、StatefulShellRoute でタブ管理）
    StatefulShellRoute.indexedStack(
      builder: (context, state, navigationShell) {
        return HomePage(navigationShell: navigationShell);
      },
      branches: [
        // Sessions タブ
        StatefulShellBranch(
          routes: [
            GoRoute(
              path: '/sessions',
              builder: (context, state) => const SessionsPage(),
              routes: [
                GoRoute(
                  path: 'add',
                  builder: (context, state) => const AddSessionPage(),
                ),
                GoRoute(
                  path: 'filter',
                  builder: (context, state) => const SessionFilterPage(),
                ),
                GoRoute(
                  path: ':sessionId',
                  builder: (context, state) => SessionDetailsPage(
                    sessionId: state.pathParameters['sessionId']!,
                    session: state.extra as Session?,
                  ),
                  routes: [
                    GoRoute(
                      path: 'edit',
                      builder: (context, state) => EditSessionPage(
                        originalSession: state.extra as Session?,
                      ),
                    ),
                    GoRoute(
                      path: 'resource/:resourceId',
                      builder: (context, state) => ResourceDetailsPage(
                        sessionId: state.pathParameters['sessionId']!,
                        resourceId: state.pathParameters['resourceId']!,
                        session: (state.extra as Map)['session'] as Session,
                      ),
                    ),
                  ],
                ),
              ],
            ),
          ],
        ),

        // Players タブ
        StatefulShellBranch(
          routes: [
            GoRoute(
              path: '/players',
              builder: (context, state) {
                final ref = ProviderScope.containerOf(context);
                final isSingleTeam = /* check logic */;
                return isSingleTeam
                    ? SingleTeamPlayerPage()
                    : const PlayersPage();
              },
              routes: [
                GoRoute(
                  path: 'create',
                  builder: (context, state) => const CreatePlayerPage(),
                ),
                GoRoute(
                  path: 'edit',
                  builder: (context, state) => EditPlayerPage(
                    player: state.extra as Player,
                  ),
                ),
              ],
            ),
          ],
        ),

        // Admin タブ（権限ベース）
        StatefulShellBranch(
          routes: [
            GoRoute(
              path: '/admin',
              redirect: _adminRedirect, // 権限チェック
              builder: (context, state) => const AdminPage(),
              routes: [
                GoRoute(
                  path: 'edit-team',
                  builder: (context, state) => const EditTeamPage(),
                ),
                GoRoute(
                  path: 'edit-member',
                  builder: (context, state) => EditMemberPage(
                    member: state.extra,
                  ),
                ),
                GoRoute(
                  path: 'invite-member',
                  builder: (context, state) => const InviteMemberPage(),
                ),
              ],
            ),
          ],
        ),

        // Settings タブ
        StatefulShellBranch(
          routes: [
            GoRoute(
              path: '/settings',
              builder: (context, state) => const SettingsPage(),
              routes: [
                GoRoute(
                  path: 'edit-profile',
                  builder: (context, state) => const EditProfilePage(),
                ),
                GoRoute(
                  path: 'change-password',
                  builder: (context, state) => const ChangePasswordPage(),
                ),
                GoRoute(
                  path: 'change-units',
                  builder: (context, state) => const ChangeUnitsPage(),
                ),
                GoRoute(
                  path: 'license',
                  builder: (context, state) => const CustomLicensePage(),
                ),
                GoRoute(
                  path: 'license-checker',
                  builder: (context, state) => const LicenseCheckerPage(),
                ),
                GoRoute(
                  path: 'notifications',
                  builder: (context, state) => const NotificationListPage(),
                  routes: [
                    GoRoute(
                      path: ':notificationId',
                      builder: (context, state) => NotificationDetailsPage(
                        notification: state.extra,
                      ),
                    ),
                  ],
                ),
              ],
            ),
          ],
        ),
      ],
    ),

    // フルスクリーンページ（タブ外）
    GoRoute(
      path: '/recording',
      parentNavigatorKey: _rootNavigatorKey,
      builder: (context, state) {
        final params = state.extra as RecordingPageParams;
        return RecordingPage(
          sessionId: params.sessionId,
          sessionCreatedAt: params.sessionCreatedAt,
          teamId: params.teamId,
        );
      },
    ),
    GoRoute(
      path: '/video-player-fullscreen',
      parentNavigatorKey: _rootNavigatorKey,
      builder: (context, state) {
        final params = state.extra as VideoPlayerParams;
        return VideoPlayerFullScreenPage(
          ball: params.ball,
          videoURL: params.videoURL,
          fileName: params.fileName,
          isShareAvailable: params.isShareAvailable,
        );
      },
    ),

    // サブスクリプション関連
    GoRoute(
      path: '/subscription',
      parentNavigatorKey: _rootNavigatorKey,
      pageBuilder: (context, state) {
        final params = state.extra as SubscriptionPageParams;
        return CustomTransitionPage(
          key: state.pageKey,
          child: SubscriptionPage(
            team: params.team,
            currentPlan: params.currentPlan,
          ),
          transitionsBuilder: _slideUpTransition,
          transitionDuration: const Duration(milliseconds: 400),
          reverseTransitionDuration: const Duration(milliseconds: 200),
        );
      },
    ),
    GoRoute(
      path: '/cancel-subscription',
      builder: (context, state) => const CancelSubscriptionPage(),
    ),

    // アカウント管理
    GoRoute(
      path: '/delete-account',
      builder: (context, state) => DeleteAccountPage(
        shouldShowCancelSubscriptionMessage:
            (state.extra as Map?)?['shouldShowCancelSubscriptionMessage'] ?? false,
      ),
    ),

    // デバッグページ
    GoRoute(
      path: '/iap-debug',
      builder: (context, state) => const InAppPurchaseDebugPage(),
    ),
  ],
);
```

### リダイレクトロジック

```dart
String? _globalRedirect(BuildContext context, GoRouterState state) {
  final ref = ProviderScope.containerOf(context);

  // システムチェック（優先度高）
  if (Constants.isDeprecated && state.matchedLocation != '/force-migration') {
    return '/force-migration';
  }

  final maintenance = ref.read(maintenanceControllerProvider);
  if (maintenance.value?.isInMaintenance == true &&
      state.matchedLocation != '/maintenance') {
    return '/maintenance';
  }

  final version = ref.read(versionControllerProvider);
  if (version.value?.isRight == true &&
      version.value!.right.isUpdateRequired &&
      state.matchedLocation != '/update-required') {
    return '/update-required';
  }

  // 認証チェック（優先度低）
  final isPublicRoute = [
    '/splash',
    '/force-migration',
    '/maintenance',
    '/update-required',
    '/onboarding',
    '/login',
    '/signup',
  ].any((route) => state.matchedLocation.startsWith(route));

  if (!isPublicRoute) {
    final authClient = ref.read(authClientProvider);
    final isLoggedIn = authClient.isLoggedIn; // 同期版を用意する必要がある

    if (!isLoggedIn) {
      return '/login';
    }
  }

  return null;
}

String? _adminRedirect(BuildContext context, GoRouterState state) {
  final ref = ProviderScope.containerOf(context);
  final accessibleContents = ref.read(userAccessibleContentsControllerProvider);
  final teamId = ref.read(profileStorageProvider).getTeamId();

  if (accessibleContents == null || teamId == null) {
    return '/sessions';
  }

  if (!accessibleContents.hasPrivilegesFor(
      teamId, RoleDomain.management, RoleLevel.read, true)) {
    return '/sessions';
  }

  return null;
}
```

